        if (input == null) {
            input = "";
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT * FROM ledger_entries WHERE memo = '" + input + "'";
            try (PreparedStatement ps = conn.prepareStatement(sql);
